INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57112235-moex-00607', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄受刑人之財物保管，下列敘述何者正確？', '["監獄代為保管受刑人之金錢，應設專戶管理，其所孳生之利息，統籌運用於改善監獄各項設施", "監獄對外界送入之金錢、飲食及物品，如受刑人拒絕收受者應退回之，無法退回者，經公告3個月 後，仍無人領取時，歸屬國庫或毀棄", "受刑人脫逃者，自脫逃之日起算，經6個月後，未申請發還者，其所留之金錢及物品，予以歸屬國 庫、毀棄或另為其他適當處理", "受刑人死亡後遺留之金錢及物品，應無限期通知所有家屬領回"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00608', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄假釋審查，下列敘述何者錯誤？', '["法務部對監獄陳報之假釋案件，應為許可假釋或不予許可假釋之處分", "監獄對於受刑人符合假釋要件者，應提報其假釋審查會決議後，報請法務部審查", "依刑法第77條第2項第3款接受強制身心治療或輔導教育之受刑人，如顯有再犯之虞，不得報請 假釋", "經法務部不予許可假釋之處分案，除進級者外，監獄應逾3月即得再行陳報"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00609', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄對受刑人施以隔離保護，下列敘述何者錯誤？', '["施以隔離保護應經監獄長官核准。但情況緊急時，得先行為之，並立即報告監獄長官", "隔離保護時間最長不得逾15日", "施以隔離保護後應以書面告知受刑人外，應通知其家屬或最近親屬", "戒護人員經觀察其身心狀況，認為不適宜繼續隔離保護者，應停止之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00610', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄對於新入監者，應就其個性、身心狀況、經歷、教育程度及其他相關事項，加以調查，有關其調 查期間之規定，下列敘述何者正確？', '["不得逾2個月", "不得逾3個月", "不得逾4個月", "不得逾5個月"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00611', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄適用累進處遇之受刑人，得給予和緩處遇之情形，下列敘述何者錯誤？', '["患有疾病經醫師證明需長期療養", "衰老、身心障礙、行動不便或不能自理生活", "懷胎期間或生產未滿4月", "有客觀事實足認其身心狀況欠缺辨識能力，致不能處理自己事務，或其辨識能力顯著減低"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00612', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '遇有天災、事變在監獄內無法防避時，不及護送於相當處所時，得暫行釋放。對於暫行釋放之受刑人， 由離監時起多少時間內，需至該監或警察機關報到之規定，下列何者正確？', '["48小時", "60小時", "72小時", "84小時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00613', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄處理申訴事件之審議小組委員，於申訴事件有應自行迴避之情形，下列敘述何者錯誤？', '["現為或曾為申訴人之配偶", "為申訴人四親等內之血親", "現為或曾為申訴人四親等之姻親", "現為或曾為申訴人之代理人、辯護人、輔佐人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00614', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '法務部為處理假釋之處分復審事件，應設復審審議小組，有關其設置及開會之相關規定，下列敘述 何者錯誤？', '["置委員9人，由法務部或所屬機關代表4人、學者專家或社會公正人士5人組成之", "由部長指定之委員為主席，其中任一性別委員不得少於3分之1", "復審審議小組須有全體委員過3分之2出席，始得開會", "決議以出席人數過半數同意行之，可否同數時，取決於主席"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00615', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄行刑法衛生及醫療之規定，下列敘述何者錯誤？', '["監獄依其規模及收容對象、特性，得在資源可及範圍內備置相關醫事人員，於夜間及假日為戒護外 醫之諮詢判斷", "監獄除國定例假日、休息日或有特殊事由外，應給予受刑人每日運動1小時", "受刑人或其最近親屬及家屬，在不妨礙監獄秩序及經醫師評估有必要之情形下，得請求監獄准許自 費延請醫事人員於監獄內實施健康檢查", "受刑人因受傷或罹患疾病，拒不就醫，致有生命危險之虞，監獄應即請醫師逕行救治或將受刑人逕 送醫療機構治療。其逕送醫療機構治療之醫療及交通費用，由監獄負擔"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00616', 'judicial-57112235', 'judicial-57112235-moex-111-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄為處理申訴事件，應設申訴審議小組，有關申訴審議小組之作為，下列敘述何者正確？', '["審議小組置委員9人，經監督機關核定後，由典獄長指派之代表3人及學者專家或社會公正人士6 人組成之", "審議小組認為申訴書不合法定程式，而其情形可補正者，應通知申訴人於10日內補正", "審議小組須有全體委員過半數之出席，始得開會；其決議以出席人數過3分之2同意行之", "審議小組應自受理申訴之次日起30日內作成決定，必要時得延長30日，並通知申訴人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:52+00:00", "source_pdf_sha1": "95b9205e8544", "answer_pdf_sha1": "6055fa1f5814", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "206", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
